mapper.select:
    	/* com.erns.coching.message.mapper.MessageDAO.getList */

    	SELECT B.* FROM (
			SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() AS TOTAL FROM (
					SELECT

				    FROM  T_MESSAGE_INF AA



			) A
		) B

	    	WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

mapper.insert:
    	/* com.erns.coching.message.mapper.MessageDAO.insert */


			SELECT nextval('seq_t_message_inf')


    	INSERT INTO T_MESSAGE_INF (
			  RAW_SEQ
			, MESSAGE_SEQ
			, SENDER
			, RECEIVER
			, CONTENT
			, STATE
			, SECRET_YN
			, RAW_REQUEST_SEQ
			, BLOCK_YN
			, RGT_DTTM
    	) VALUES (
			  #{rawSeq		, jdbcType=INTEGER}
			, #{messageSeq	, jdbcType=INTEGER}
			, #{rgtr		, jdbcType=INTEGER}
			, #{receiver	, jdbcType=INTEGER}
			, #{content		, jdbcType=VARCHAR}
			, COALESCE(#{state	, jdbcType=VARCHAR}, '0')
			, #{secretYn		, jdbcType=VARCHAR}
			, #{rawRequestSeq	, jdbcType=INTEGER}
			, COALESCE(#{blockYn, jdbcType=VARCHAR}, '0')
			, now()
    	)

mapper.update:
    	/* com.erns.coching.message.mapper.MessageDAO.updateState */

    	UPDATE T_MESSAGE_INF SET
			  STATE				= COALESCE(#{state	, jdbcType=VARCHAR}, '0')

			AND MESSAGE_SEQ		= #{messageSeq	, jdbcType=INTEGER}

mapper.delete:
/* com.erns.coching.message.mapper.MessageDAO.delete */

DELETE FROM T_MESSAGE_INF

	AND MESSAGE_SEQ 	= #{messageSeq	, jdbcType=INTEGER}
